// src/App.js
import React, { useState, useEffect } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useNavigate,
} from "react-router-dom";
import { onAuthChange, logoutUser } from "./utils/firebase";

import Sidebar from "./components/Sidebar";
import DashboardPage from "./pages/DashboardPage";
import PracticePage from "./pages/PracticePage";
import ResultsPage from "./pages/ResultsPage";
import LandingPage from "./pages/LandingPage";

import "./App.css";

function AppShell({ user, onLogout }) {
  const navigate = useNavigate();
  const [analysisData, setAnalysisData] = useState(null);

  const legacyNavigate = (page, data = null) => {
    if (data) setAnalysisData(data);

    const routeMap = {
      landing: "/",
      dashboard: "/dashboard",
      practice: "/practice",
      scenarios: "/scenarios",
      progress: "/progress",
      settings: "/settings",
      results: "/results",
    };

    navigate(routeMap[page] ?? "/dashboard");
  };

  return (
    <div className="app-shell">
      {user && <Sidebar user={user} onLogout={onLogout} />}

      <main className={`app-content${user ? " with-sidebar" : ""}`}>
        <Routes>
          <Route
            path="/"
            element={
              user ? (
                <Navigate to="/dashboard" replace />
              ) : (
                <LandingPage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              )
            }
          />

          <Route
            path="/dashboard"
            element={
              user ? (
                <DashboardPage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/practice"
            element={
              user ? (
                <PracticePage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/scenarios"
            element={
              user ? (
                <PracticePage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/progress"
            element={
              user ? (
                <DashboardPage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/settings"
            element={
              user ? (
                <DashboardPage
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/results"
            element={
              user ? (
                <ResultsPage
                  results={analysisData}
                  navigate={legacyNavigate}
                  user={user}
                  onLogout={onLogout}
                />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="*"
            element={<Navigate to={user ? "/dashboard" : "/"} replace />}
          />
        </Routes>
      </main>
    </div>
  );
}

export default function App() {
  const [user, setUser] = useState(undefined);

  useEffect(() => {
    const unsub = onAuthChange((firebaseUser) => {
      setUser(firebaseUser);
    });

    return () => unsub();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    setUser(null);
  };

  if (user === undefined) {
    return (
      <div className="app-loading">
        <div className="spinner" />
      </div>
    );
  }

  return (
    <BrowserRouter>
      <AppShell user={user} onLogout={handleLogout} />
    </BrowserRouter>
  );
}
